from math import gcd
def lcm(a, b):
    return a * b // gcd(a, b)

def main():
    n, m = map(int, input().split())
    a = list(map(int, input().split()))
    l = 1
    k = 0
    for i in range(n):
        l = lcm(l, a[i])
        if l > m:
            break
        k += 1
    print(l, k)
    for i in range(n):
        if lcm(l, a[i]) == l:
            print(i+1, end=' ')
    print()

if __name__ == '__main__':
    main()
